  const itemRefs = useRef(new Map<string, HTMLButtonElement | null>());

  // Keep the active card in view as the timeline / map drive the selection.
  useEffect(() => {
    const node = itemRefs.current.get(selectedMapId);
    node?.scrollIntoView({ block: "nearest" });
  }, [selectedMapId]);

  return (
    <aside
      className={cn(
        "bg-background flex h-full w-full flex-col border-r md:w-[360px]",
        className,
      )}
    >
      <div className="space-y-3 border-b p-4">
        <div className="flex items-center justify-between gap-2">
          <div className="flex items-center gap-2">
            <span className="grid size-7 place-items-center rounded-md bg-[#ab1000] text-white">
              <MapPin className="size-4" />
            </span>
            <div className="leading-tight">
              <p className="text-sm font-semibold tracking-tight">
                OldMapsOnline
              </p>
              <p className="text-muted-foreground text-[11px]">
                Historical map explorer
              </p>
            </div>
          </div>
          {onClose ? (
            <button
              type="button"
              aria-label="Close results"
              onClick={onClose}
              className="hover:bg-muted text-muted-foreground grid size-8 place-items-center rounded-md md:hidden"
            >
              <X className="size-4" />
            </button>
          ) : null}
        </div>

        <div className="relative">
          <Search className="text-muted-foreground pointer-events-none absolute top-1/2 left-2.5 size-4 -translate-y-1/2" />
          <input
            value={query}
            onChange={(event) => onQueryChange(event.target.value)}
            placeholder="Search places or cartographers"
            aria-label="Search maps"
            className="border-input bg-background focus-visible:ring-ring h-9 w-full rounded-md border pr-3 pl-8 text-sm shadow-sm outline-none focus-visible:ring-2"
          />
        </div>

        <div className="text-muted-foreground flex items-center justify-between text-xs">
          <span>
            <span className="text-foreground font-medium">{maps.length}</span>{" "}
            of {totalCount} maps
          </span>
          <span>around {year}</span>
        </div>
      </div>

      <div className="min-h-0 flex-1 overflow-y-auto">
        {maps.length === 0 ? (
          <p className="text-muted-foreground p-6 text-center text-sm">
            No maps match this period. Try dragging the timeline or clearing the
            search.
          </p>
        ) : (
          <ul className="divide-y">
            {maps.map((map) => {
              const selected = map.id === selectedMapId;
              const hovered = map.id === hoveredMapId;
              return (
                <li key={map.id}>
                  <button
                    type="button"
                    ref={(node) => {
                      itemRefs.current.set(map.id, node);
                    }}
                    onClick={() => onSelectMap(map.id)}
                    onMouseEnter={() => onHoverMap(map.id)}
                    onMouseLeave={() => onHoverMap(null)}
                    onFocus={() => onHoverMap(map.id)}
                    onBlur={() => onHoverMap(null)}
                    className={cn(
                      "flex w-full gap-3 border-l-2 border-transparent px-4 py-3 text-left transition-colors",
                      hovered && !selected && "bg-muted/60",
                      selected && "border-l-[#ab1000] bg-[#ab1000]/10",
                    )}
                  >
                    <span
                      className={cn(
                        "size-14 shrink-0 overflow-hidden rounded-sm border shadow-sm",
                        selected && "ring-2 ring-[#ab1000]",
                      )}
                    >
                      <MapThumbnail seed={map.id} />
                    </span>
                    <span className="min-w-0 flex-1">
                      <span className="line-clamp-2 text-sm leading-snug font-medium">
                        {map.title}
                      </span>
                      <span className="text-muted-foreground mt-0.5 flex items-center gap-1.5 text-xs">
                        <span className="text-foreground tabular-nums">
                          {map.year}
                        </span>
                        <span aria-hidden>·</span>
                        <span className="truncate">{map.place}</span>
                      </span>
                      <span className="text-muted-foreground mt-0.5 block truncate text-xs">
                        {map.author}
                      </span>
                      <span className="text-muted-foreground/80 mt-1 flex items-center gap-1.5 text-[11px]">
                        <span className="bg-muted truncate rounded px-1.5 py-0.5">
                          {map.scale}
                        </span>
                        <span className="truncate">{map.archive}</span>
                      </span>
                    </span>
                  </button>
                </li>
              );
            })}
          </ul>
        )}
      </div>
    </aside>
  );
}

"use client";

import { useMemo } from "react";

import { cn } from "@/lib/utils";

/**
 * A deterministic, parchment-styled "old map" thumbnail rendered entirely in
 * SVG. There are no external assets, so each result card gets a distinct,
 * stable illustration derived from its id — a stand-in for the scanned map
 * thumbnails OldMapsOnline shows in its results list.
 */
function hashString(value: string) {
  let hash = 2166136261;
  for (let i = 0; i < value.length; i += 1) {
    hash ^= value.charCodeAt(i);
    hash = Math.imul(hash, 16777619);
  }
  return hash >>> 0;
}

function mulberry32(seed: number) {
  let a = seed;
  return () => {
    a |= 0;
    a = (a + 0x6d2b79f5) | 0;
    let t = Math.imul(a ^ (a >>> 15), 1 | a);
    t = (t + Math.imul(t ^ (t >>> 7), 61 | t)) ^ t;
    return ((t ^ (t >>> 14)) >>> 0) / 4294967296;
  };
}

export function MapThumbnail({
  seed,
  className,
}: {
  seed: string;
  className?: string;
}) {
  const { coast, rivers, graticule, hue } = useMemo(() => {
    const rand = mulberry32(hashString(seed));
    const size = 64;

    // A wandering coastline that divides "land" from "sea".
    const points: string[] = [];
    let y = 14 + rand() * 14;
    for (let x = 0; x <= size; x += 8) {
      y += (rand() - 0.5) * 14;
      y = Math.max(8, Math.min(size - 8, y));
      points.push(`${x},${y.toFixed(1)}`);
    }
    const coast = `M0,${size} L0,${points[0].split(",")[1]} ${points
      .map((p) => `L${p}`)
      .join(" ")} L${size},${size} Z`;

    // A couple of meandering rivers.
    const rivers: string[] = [];
    const riverCount = 1 + Math.floor(rand() * 2);
    for (let r = 0; r < riverCount; r += 1) {
      let rx = 10 + rand() * (size - 20);
      let ry = size;
      let path = `M${rx.toFixed(1)},${ry}`;
      while (ry > 6) {
        ry -= 7 + rand() * 5;
        rx += (rand() - 0.5) * 16;
        rx = Math.max(4, Math.min(size - 4, rx));
        path += ` L${rx.toFixed(1)},${ry.toFixed(1)}`;
      }
      rivers.push(path);
    }

    const graticule = [16, 32, 48];
    const hue = 28 + Math.floor(rand() * 18); // warm sepia range
    return { coast, rivers, graticule, hue };
  }, [seed]);

  return (
    <svg
      viewBox="0 0 64 64"
      className={cn("h-full w-full", className)}
      role="img"
      aria-hidden="true"
    >
      <rect width="64" height="64" fill={`hsl(${hue} 44% 86%)`} />
      <path d={coast} fill={`hsl(${hue} 34% 78%)`} />
      {graticule.map((g) => (
        <g key={g} stroke={`hsl(${hue} 30% 64%)`} strokeWidth="0.4" opacity="0.5">
          <line x1={g} y1="0" x2={g} y2="64" />
          <line x1="0" y1={g} x2="64" y2={g} />
        </g>
      ))}
      {rivers.map((d, i) => (
        <path
          key={i}
          d={d}
          fill="none"
          stroke={`hsl(${hue} 36% 52%)`}
          strokeWidth="0.9"
          strokeLinecap="round"
          opacity="0.8"
        />
      ))}
      <circle
        cx="50"
        cy="14"
        r="5"
        fill="none"
        stroke={`hsl(${hue} 40% 40%)`}
        strokeWidth="0.7"
        opacity="0.7"
      />
      <path
        d="M50,9 L51.4,14 L50,19 L48.6,14 Z"
        fill={`hsl(${hue} 40% 40%)`}
        opacity="0.7"
      />
      <rect
        x="1"
        y="1"
        width="62"
        height="62"
        fill="none"
        stroke={`hsl(${hue} 38% 46%)`}
        strokeWidth="1.4"
        opacity="0.65"
      />
    </svg>
  );
}

"use client";

import { useEffect, useMemo } from "react";
import type MapLibreGL from "maplibre-gl";

import { useMap } from "@/components/ui/map";
import { footprintCollection, type HistoricalMapRecord } from "../data";

type MapFootprintsProps = {
  maps: HistoricalMapRecord[];
  selectedMapId: string;
  hoveredMapId: string | null;
  onSelectMap: (id: string) => void;
  onHoverMap: (id: string | null) => void;
};

const SOURCE_ID = "old-maps-footprints";
const FILL_ID = "old-maps-footprints-fill";
const LINE_ID = "old-maps-footprints-line";

// State-driven styling keeps fills subtle until a sheet is hovered/selected.
const fillColor: MapLibreGL.ExpressionSpecification = [
  "match",
  ["get", "state"],
  "selected",
  "#ab1000",
  "hovered",
  "#e7903a",
  "#675c44",
];
const fillOpacity: MapLibreGL.ExpressionSpecification = [
  "match",
  ["get", "state"],
  "selected",
  0.22,
  "hovered",
  0.16,
  0.05,
];
const lineWidth: MapLibreGL.ExpressionSpecification = [
  "match",
  ["get", "state"],
  "selected",
  2.5,
  "hovered",
  1.75,
  1,
];
const lineOpacity: MapLibreGL.ExpressionSpecification = [
  "match",
  ["get", "state"],
  "selected",
  1,
  "hovered",
  0.9,
  0.4,
];

/** Draws coverage rectangles for each historical map sheet on the basemap. */
export function MapFootprints({
  maps,
  selectedMapId,
  hoveredMapId,
  onSelectMap,
  onHoverMap,
}: MapFootprintsProps) {
  const { map, isLoaded } = useMap();

  const data = useMemo(
    () => footprintCollection(maps, selectedMapId, hoveredMapId),
    [maps, selectedMapId, hoveredMapId],
  );

  // Create the source + layers, and re-create them if the style reloads
  // (e.g. on a light/dark theme switch, which discards custom layers).
  useEffect(() => {
    if (!isLoaded || !map) return;

    const ensureLayers = () => {
      if (!map.getSource(SOURCE_ID)) {
        map.addSource(SOURCE_ID, { type: "geojson", data });
      }
      if (!map.getLayer(FILL_ID)) {
        map.addLayer({
          id: FILL_ID,
          type: "fill",
          source: SOURCE_ID,
          paint: { "fill-color": fillColor, "fill-opacity": fillOpacity },
        });
      }
      if (!map.getLayer(LINE_ID)) {
        map.addLayer({
          id: LINE_ID,
          type: "line",
          source: SOURCE_ID,
          layout: { "line-join": "round" },
          paint: {
            "line-color": fillColor,
            "line-width": lineWidth,
            "line-opacity": lineOpacity,
          },
        });
      }
    };

    ensureLayers();
    map.on("styledata", ensureLayers);

    return () => {
      map.off("styledata", ensureLayers);
      try {
        if (map.getLayer(LINE_ID)) map.removeLayer(LINE_ID);
        if (map.getLayer(FILL_ID)) map.removeLayer(FILL_ID);
        if (map.getSource(SOURCE_ID)) map.removeSource(SOURCE_ID);
      } catch {
        // style already torn down — nothing to clean up
      }
    };
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [isLoaded, map]);

  // Push fresh state into the source whenever selection / hover / set changes.
  useEffect(() => {
    if (!isLoaded || !map) return;
    const source = map.getSource(SOURCE_ID) as
      | MapLibreGL.GeoJSONSource
      | undefined;
    source?.setData(data);
  }, [isLoaded, map, data]);

  // Interactions: clicking a footprint selects it, hovering highlights it.
  useEffect(() => {
    if (!isLoaded || !map) return;

    const handleClick = (
      event: MapLibreGL.MapMouseEvent & {
        features?: MapLibreGL.MapGeoJSONFeature[];
      },
    ) => {
      const id = event.features?.[0]?.properties?.id;
      if (typeof id === "string") onSelectMap(id);
    };
    const handleMove = (
      event: MapLibreGL.MapMouseEvent & {
        features?: MapLibreGL.MapGeoJSONFeature[];
      },
    ) => {
      const id = event.features?.[0]?.properties?.id;
      map.getCanvas().style.cursor = "pointer";
      if (typeof id === "string") onHoverMap(id);
    };
    const handleLeave = () => {
      map.getCanvas().style.cursor = "";
      onHoverMap(null);
    };

    map.on("click", FILL_ID, handleClick);
    map.on("mousemove", FILL_ID, handleMove);
    map.on("mouseleave", FILL_ID, handleLeave);

    return () => {
      map.off("click", FILL_ID, handleClick);
      map.off("mousemove", FILL_ID, handleMove);
      map.off("mouseleave", FILL_ID, handleLeave);
    };
  }, [isLoaded, map, onSelectMap, onHoverMap]);

  return null;
}
